// Parse VAPI End-of-Call Report
// Extracts all structured data, transcript, metadata
const data = $input.first().json;
const body = data.body || data;
const message = body.message || body;

const messageType = message.type || body.type || '';
const isEOCR = messageType === 'end-of-call-report';

if (!isEOCR) {
  return [{ json: { skip: true, reason: 'Not EOCR: ' + messageType } }];
}

const call = message.call || body.call || {};
const artifact = message.artifact || body.artifact || {};
const analysis = message.analysis || body.analysis || {};
const sd = analysis.structuredData || {};

const callId = call.id || '';
const customerNumber = call.customer?.number || message.customer?.number || '';
const assistantId = call.assistantId || message.assistantId || '';
const phoneNumberId = call.phoneNumberId || '';
const phoneNumber = call.phoneNumber?.number || '';
const duration = message.durationSeconds || call.costBreakdown?.duration || 0;
const cost = call.costBreakdown?.total || call.cost || 0;
const endedReason = call.endedReason || message.endedReason || '';
const transcript = (artifact.transcript || '').substring(0, 8000);
const recordingUrl = artifact.recordingUrl || '';
const summary = (analysis.summary || '').substring(0, 2000);
const successEval = analysis.successEvaluation || '';

return [{ json: {
  skip: false,
  callId,
  customerNumber,
  assistantId,
  phoneNumberId,
  phoneNumber,
  duration,
  cost,
  endedReason,
  transcript,
  recordingUrl,
  summary,
  successEval,
  structuredData: sd,
  rawAnalysis: analysis,
  timestamp: new Date().toISOString()
} }];

// Lookup client config from Supabase by assistant_id or phone_number
// Uses array containment operator @> for matching
const d = $input.first().json;
const assistantId = d.assistantId;
const phoneNumber = d.phoneNumber;

const SUPABASE_URL = '{{SUPABASE_URL}}';
const SUPABASE_KEY = '{{SUPABASE_SERVICE_KEY}}';

// Try assistant_id first
let config = null;
if (assistantId) {
  const resp = await this.helpers.httpRequest({
    method: 'GET',
    url: `${SUPABASE_URL}/rest/v1/client_configs?vapi_assistant_ids=cs.{${assistantId}}&limit=1`,
    headers: {
      'apikey': SUPABASE_KEY,
      'Authorization': `Bearer ${SUPABASE_KEY}`,
      'Content-Type': 'application/json'
    }
  });
  if (Array.isArray(resp) && resp.length > 0) config = resp[0];
}

// Fallback: try phone_number
if (!config && phoneNumber) {
  const resp = await this.helpers.httpRequest({
    method: 'GET',
    url: `${SUPABASE_URL}/rest/v1/client_configs?vapi_phone_numbers=cs.{${phoneNumber}}&limit=1`,
    headers: {
      'apikey': SUPABASE_KEY,
      'Authorization': `Bearer ${SUPABASE_KEY}`,
      'Content-Type': 'application/json'
    }
  });
  if (Array.isArray(resp) && resp.length > 0) config = resp[0];
}

if (!config) {
  return [{ json: {
    ...d,
    clientFound: false,
    clientId: null,
    clientName: 'UNKNOWN',
    crmType: 'none',
    crmApiKey: null,
    crmBaseUrl: null,
    crmFieldMapping: {},
    notificationType: 'none',
    notificationTarget: null
  } }];
}

return [{ json: {
  ...d,
  clientFound: true,
  clientId: config.id,
  clientName: config.client_name,
  crmType: config.crm_type || 'none',
  crmApiKey: config.crm_api_key || null,
  crmBaseUrl: config.crm_base_url || null,
  crmFieldMapping: config.crm_field_mapping || {},
  notificationType: config.notification_type || 'none',
  notificationTarget: config.notification_target || null
} }];

// HubSpot CRM push
// Creates or updates a contact, then logs a call activity
const d = $input.first().json;
const apiKey = d.crmApiKey;
const mapping = d.crmFieldMapping || {};
const sd = d.structuredData || {};

// Build contact properties from field mapping
const properties = {};
for (const [vapiField, hubspotField] of Object.entries(mapping)) {
  const value = sd[vapiField] ?? d[vapiField];
  if (value !== undefined && value !== null && value !== '') {
    properties[hubspotField] = String(value);
  }
}

// Always include phone
if (d.customerNumber && !properties.phone) {
  properties.phone = d.customerNumber;
}

let contactId = null;
let action = 'created';

try {
  // Search for existing contact by phone
  const searchResp = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.hubapi.com/crm/v3/objects/contacts/search',
    headers: {
      'Authorization': `Bearer ${apiKey}`,
      'Content-Type': 'application/json'
    },
    body: JSON.stringify({
      filterGroups: [{
        filters: [{
          propertyName: 'phone',
          operator: 'EQ',
          value: d.customerNumber
        }]
      }],
      limit: 1
    })
  });

  if (searchResp.total > 0) {
    contactId = searchResp.results[0].id;
    action = 'updated';
    // Update existing contact
    await this.helpers.httpRequest({
      method: 'PATCH',
      url: `https://api.hubapi.com/crm/v3/objects/contacts/${contactId}`,
      headers: {
        'Authorization': `Bearer ${apiKey}`,
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({ properties })
    });
  } else {
    // Create new contact
    const createResp = await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://api.hubapi.com/crm/v3/objects/contacts',
      headers: {
        'Authorization': `Bearer ${apiKey}`,
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({ properties })
    });
    contactId = createResp.id;
  }

  // Log call as engagement
  await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.hubapi.com/crm/v3/objects/calls',
    headers: {
      'Authorization': `Bearer ${apiKey}`,
      'Content-Type': 'application/json'
    },
    body: JSON.stringify({
      properties: {
        hs_timestamp: d.timestamp,
        hs_call_body: d.summary || 'AI call',
        hs_call_duration: String(Math.round((d.duration || 0) * 1000)),
        hs_call_direction: 'OUTBOUND',
        hs_call_status: 'COMPLETED'
      },
      associations: [{
        to: { id: contactId },
        types: [{ associationCategory: 'HUBSPOT_DEFINED', associationTypeId: 194 }]
      }]
    })
  });

  return [{ json: { ...d, crmPushed: true, crmAction: action, crmContactId: contactId, crmError: null } }];
} catch (err) {
  return [{ json: { ...d, crmPushed: false, crmAction: 'error', crmContactId: contactId, crmError: err.message || String(err) } }];
}

// Salesforce CRM push
// Creates or updates a Lead, then logs a Task for the call
const d = $input.first().json;
const apiKey = d.crmApiKey;
const baseUrl = d.crmBaseUrl || 'https://login.salesforce.com';
const mapping = d.crmFieldMapping || {};
const sd = d.structuredData || {};

// Build field map
const fields = {};
for (const [vapiField, sfField] of Object.entries(mapping)) {
  const value = sd[vapiField] ?? d[vapiField];
  if (value !== undefined && value !== null && value !== '') {
    fields[sfField] = typeof value === 'object' ? JSON.stringify(value) : value;
  }
}

if (d.customerNumber && !fields.Phone) {
  fields.Phone = d.customerNumber;
}

try {
  // Query for existing Lead by phone
  const phone = d.customerNumber;
  const queryResp = await this.helpers.httpRequest({
    method: 'GET',
    url: `${baseUrl}/services/data/v59.0/query?q=${encodeURIComponent(`SELECT Id FROM Lead WHERE Phone = '${phone}' LIMIT 1`)}`,
    headers: {
      'Authorization': `Bearer ${apiKey}`,
      'Content-Type': 'application/json'
    }
  });

  let leadId = null;
  let action = 'created';

  if (queryResp.totalSize > 0) {
    leadId = queryResp.records[0].Id;
    action = 'updated';
    await this.helpers.httpRequest({
      method: 'PATCH',
      url: `${baseUrl}/services/data/v59.0/sobjects/Lead/${leadId}`,
      headers: {
        'Authorization': `Bearer ${apiKey}`,
        'Content-Type': 'application/json'
      },
      body: JSON.stringify(fields)
    });
  } else {
    if (!fields.LastName) fields.LastName = 'Unknown';
    if (!fields.Company) fields.Company = 'Unknown';
    const createResp = await this.helpers.httpRequest({
      method: 'POST',
      url: `${baseUrl}/services/data/v59.0/sobjects/Lead`,
      headers: {
        'Authorization': `Bearer ${apiKey}`,
        'Content-Type': 'application/json'
      },
      body: JSON.stringify(fields)
    });
    leadId = createResp.id;
  }

  // Log call as Task
  await this.helpers.httpRequest({
    method: 'POST',
    url: `${baseUrl}/services/data/v59.0/sobjects/Task`,
    headers: {
      'Authorization': `Bearer ${apiKey}`,
      'Content-Type': 'application/json'
    },
    body: JSON.stringify({
      WhoId: leadId,
      Subject: 'AI Voice Call',
      Description: (d.summary || 'No summary') + '\n\nDuration: ' + Math.round(d.duration || 0) + 's',
      Status: 'Completed',
      Priority: 'Normal',
      ActivityDate: d.timestamp ? d.timestamp.split('T')[0] : new Date().toISOString().split('T')[0]
    })
  });

  return [{ json: { ...d, crmPushed: true, crmAction: action, crmContactId: leadId, crmError: null } }];
} catch (err) {
  return [{ json: { ...d, crmPushed: false, crmAction: 'error', crmContactId: null, crmError: err.message || String(err) } }];
}

// Pipedrive CRM push
// Creates or updates a Person, then logs an Activity
const d = $input.first().json;
const apiKey = d.crmApiKey;
const baseUrl = d.crmBaseUrl || 'https://api.pipedrive.com/v1';
const mapping = d.crmFieldMapping || {};
const sd = d.structuredData || {};

try {
  // Search for existing person by phone
  const searchResp = await this.helpers.httpRequest({
    method: 'GET',
    url: `${baseUrl}/persons/search?term=${encodeURIComponent(d.customerNumber)}&fields=phone&limit=1&api_token=${apiKey}`,
    headers: { 'Content-Type': 'application/json' }
  });

  let personId = null;
  let action = 'created';

  // Build person data from mapping
  const personData = {};
  for (const [vapiField, pdField] of Object.entries(mapping)) {
    const value = sd[vapiField] ?? d[vapiField];
    if (value !== undefined && value !== null && value !== '') {
      personData[pdField] = typeof value === 'object' ? JSON.stringify(value) : value;
    }
  }

  if (searchResp.data?.items?.length > 0) {
    personId = searchResp.data.items[0].item.id;
    action = 'updated';
    await this.helpers.httpRequest({
      method: 'PUT',
      url: `${baseUrl}/persons/${personId}?api_token=${apiKey}`,
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(personData)
    });
  } else {
    if (!personData.name) personData.name = sd.nombre_contacto || d.customerNumber || 'Unknown';
    personData.phone = [{ value: d.customerNumber, primary: true }];
    const createResp = await this.helpers.httpRequest({
      method: 'POST',
      url: `${baseUrl}/persons?api_token=${apiKey}`,
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(personData)
    });
    personId = createResp.data?.id;
  }

  // Log activity
  await this.helpers.httpRequest({
    method: 'POST',
    url: `${baseUrl}/activities?api_token=${apiKey}`,
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      subject: 'AI Voice Call',
      type: 'call',
      person_id: personId,
      note: (d.summary || 'No summary') + '\n\nDuration: ' + Math.round(d.duration || 0) + 's\nResult: ' + (sd.resultado || 'N/A'),
      done: 1,
      due_date: d.timestamp ? d.timestamp.split('T')[0] : new Date().toISOString().split('T')[0],
      duration: '00:' + String(Math.floor((d.duration || 0) / 60)).padStart(2, '0') + ':' + String(Math.round((d.duration || 0) % 60)).padStart(2, '0')
    })
  });

  return [{ json: { ...d, crmPushed: true, crmAction: action, crmContactId: personId, crmError: null } }];
} catch (err) {
  return [{ json: { ...d, crmPushed: false, crmAction: 'error', crmContactId: null, crmError: err.message || String(err) } }];
}

// Generic Webhook push
// Sends the full payload to client's custom webhook URL
const d = $input.first().json;
const webhookUrl = d.crmBaseUrl;
const apiKey = d.crmApiKey;
const mapping = d.crmFieldMapping || {};
const sd = d.structuredData || {};

if (!webhookUrl) {
  return [{ json: { ...d, crmPushed: false, crmAction: 'error', crmContactId: null, crmError: 'No webhook URL configured' } }];
}

// Build mapped payload
const payload = {};
if (Object.keys(mapping).length > 0) {
  for (const [vapiField, targetField] of Object.entries(mapping)) {
    const value = sd[vapiField] ?? d[vapiField];
    if (value !== undefined && value !== null) {
      payload[targetField] = value;
    }
  }
} else {
  // No mapping — send everything
  payload.callId = d.callId;
  payload.phone = d.customerNumber;
  payload.duration = d.duration;
  payload.summary = d.summary;
  payload.structuredData = sd;
  payload.timestamp = d.timestamp;
}

try {
  const headers = { 'Content-Type': 'application/json' };
  if (apiKey) headers['Authorization'] = `Bearer ${apiKey}`;

  const resp = await this.helpers.httpRequest({
    method: 'POST',
    url: webhookUrl,
    headers,
    body: JSON.stringify(payload)
  });

  return [{ json: { ...d, crmPushed: true, crmAction: 'webhook_sent', crmContactId: null, crmError: null, crmResponse: resp } }];
} catch (err) {
  return [{ json: { ...d, crmPushed: false, crmAction: 'error', crmContactId: null, crmError: err.message || String(err) } }];
}

// GoHighLevel CRM push
// Creates or updates a Contact, then logs a call note
const d = $input.first().json;
const apiKey = d.crmApiKey;
const baseUrl = d.crmBaseUrl || 'https://services.leadconnectorhq.com';
const mapping = d.crmFieldMapping || {};
const sd = d.structuredData || {};

try {
  // Search for existing contact by phone
  const phone = d.customerNumber;
  const searchResp = await this.helpers.httpRequest({
    method: 'GET',
    url: `${baseUrl}/contacts/?query=${encodeURIComponent(phone)}&limit=1`,
    headers: {
      'Authorization': `Bearer ${apiKey}`,
      'Version': '2021-07-28',
      'Content-Type': 'application/json'
    }
  });

  let contactId = null;
  let action = 'created';

  // Build contact data from mapping
  const contactData = {};
  for (const [vapiField, ghlField] of Object.entries(mapping)) {
    const value = sd[vapiField] ?? d[vapiField];
    if (value !== undefined && value !== null && value !== '') {
      contactData[ghlField] = typeof value === 'object' ? JSON.stringify(value) : value;
    }
  }

  if (!contactData.phone) contactData.phone = phone;

  if (searchResp.contacts?.length > 0) {
    contactId = searchResp.contacts[0].id;
    action = 'updated';
    await this.helpers.httpRequest({
      method: 'PUT',
      url: `${baseUrl}/contacts/${contactId}`,
      headers: {
        'Authorization': `Bearer ${apiKey}`,
        'Version': '2021-07-28',
        'Content-Type': 'application/json'
      },
      body: JSON.stringify(contactData)
    });
  } else {
    if (!contactData.name && !contactData.firstName) {
      contactData.firstName = sd.nombre_contacto || 'Unknown';
    }
    const createResp = await this.helpers.httpRequest({
      method: 'POST',
      url: `${baseUrl}/contacts/`,
      headers: {
        'Authorization': `Bearer ${apiKey}`,
        'Version': '2021-07-28',
        'Content-Type': 'application/json'
      },
      body: JSON.stringify(contactData)
    });
    contactId = createResp.contact?.id;
  }

  // Add note with call summary
  if (contactId) {
    await this.helpers.httpRequest({
      method: 'POST',
      url: `${baseUrl}/contacts/${contactId}/notes`,
      headers: {
        'Authorization': `Bearer ${apiKey}`,
        'Version': '2021-07-28',
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({
        body: `AI Voice Call\nDuration: ${Math.round(d.duration || 0)}s\nResult: ${sd.resultado || 'N/A'}\n\n${d.summary || 'No summary'}`
      })
    });
  }

  return [{ json: { ...d, crmPushed: true, crmAction: action, crmContactId: contactId, crmError: null } }];
} catch (err) {
  return [{ json: { ...d, crmPushed: false, crmAction: 'error', crmContactId: null, crmError: err.message || String(err) } }];
}

// No CRM configured — pass through with crmPushed = false
const d = $input.first().json;
return [{ json: { ...d, crmPushed: false, crmAction: 'none', crmContactId: null, crmError: null } }];

// Log call result to Supabase call_logs table
// Idempotent: upserts on vapi_call_id via on_conflict
const d = $input.first().json;

const SUPABASE_URL = '{{SUPABASE_URL}}';
const SUPABASE_KEY = '{{SUPABASE_SERVICE_KEY}}';

const row = {
  client_id: d.clientId || null,
  vapi_call_id: d.callId,
  phone_number: d.customerNumber,
  duration_seconds: d.duration || 0,
  resultado: d.structuredData?.resultado || d.crmAction || '',
  structured_data: d.structuredData || {},
  summary: d.summary || '',
  crm_pushed: d.crmPushed || false,
  crm_response: d.crmResponse || { action: d.crmAction, contactId: d.crmContactId, error: d.crmError }
};

try {
  const resp = await this.helpers.httpRequest({
    method: 'POST',
    url: `${SUPABASE_URL}/rest/v1/call_logs?on_conflict=vapi_call_id`,
    headers: {
      'apikey': SUPABASE_KEY,
      'Authorization': `Bearer ${SUPABASE_KEY}`,
      'Content-Type': 'application/json',
      'Prefer': 'resolution=merge-duplicates,return=representation'
    },
    body: JSON.stringify(row)
  });
  return [{ json: { ...d, logSaved: true, logResponse: resp } }];
} catch (err) {
  return [{ json: { ...d, logSaved: false, logError: err.message || String(err) } }];
}

// Send notification to client's configured channel
const d = $input.first().json;
const type = d.notificationType || 'none';
const target = d.notificationTarget;

if (type === 'none' || !target) {
  return [{ json: { ...d, notificationSent: false, notificationReason: 'not_configured' } }];
}

const sd = d.structuredData || {};
const resultado = sd.resultado || d.crmAction || 'unknown';
const nombre = sd.nombre_contacto || d.customerNumber || 'Unknown';
const duracion = Math.round(d.duration || 0);
const resumen = d.summary || 'No summary available';

try {
  if (type === 'slack') {
    // Slack incoming webhook
    const text = `:phone: *AI Call Completed*\n*Client:* ${d.clientName}\n*Contact:* ${nombre} (${d.customerNumber})\n*Duration:* ${duracion}s\n*Result:* ${resultado}\n*CRM:* ${d.crmPushed ? 'Pushed (' + d.crmAction + ')' : 'Not pushed'}\n\n${resumen}`;
    await this.helpers.httpRequest({
      method: 'POST',
      url: target,
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ text })
    });
    return [{ json: { ...d, notificationSent: true } }];

  } else if (type === 'email') {
    // Uses n8n's built-in SMTP or a webhook-based email service
    // For now, post to a notification webhook that sends email
    await this.helpers.httpRequest({
      method: 'POST',
      url: target,
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        to: target,
        subject: `AI Call: ${resultado} - ${nombre}`,
        body: `Client: ${d.clientName}\nContact: ${nombre} (${d.customerNumber})\nDuration: ${duracion}s\nResult: ${resultado}\nCRM Pushed: ${d.crmPushed}\n\n${resumen}`
      })
    });
    return [{ json: { ...d, notificationSent: true } }];

  } else if (type === 'whatsapp') {
    // Post to a WhatsApp webhook (e.g. n8n sub-workflow or Twilio)
    await this.helpers.httpRequest({
      method: 'POST',
      url: target,
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        phone: target,
        message: `AI Call | ${d.clientName}\n${nombre} (${d.customerNumber})\nDuration: ${duracion}s | Result: ${resultado}\nCRM: ${d.crmPushed ? 'OK' : 'Skip'}\n${resumen.substring(0, 500)}`
      })
    });
    return [{ json: { ...d, notificationSent: true } }];
  }

  return [{ json: { ...d, notificationSent: false, notificationReason: 'unknown_type: ' + type } }];
} catch (err) {
  // Notification failure should not block the flow
  return [{ json: { ...d, notificationSent: false, notificationError: err.message || String(err) } }];
}
